a.should_play = true
a.ascii_img = a.frames[1]

a.iterate = function(counting)
  if not a.should_play then
    a.ascii_img = a.frames[30]
    return
  end

  a.ascii_img = #a.frames < math.floor(counting) and a.frames[#a.frames] or a.frames[math.floor(counting)]
  Snacks.dashboard.update()
end

a.play = function()
  require("snacks").animate(1, #a.frames + 1, function(value, _)
    a.iterate(value)
  end, {
    duration = 33,
    fps = 30,
  })
end

return a
